function DoorbellHistory() {
  const [events, setEvents] = React.useState([
    { time: '2:34 PM', date: 'Today', type: 'Motion', color: '#3b82f6' },
    { time: '10:15 AM', date: 'Today', type: 'Ring', color: '#ef4444' },
    { time: '6:42 PM', date: 'Yesterday', type: 'Motion', color: '#3b82f6' },
    { time: '4:20 PM', date: 'Yesterday', type: 'Ring', color: '#ef4444' },
    { time: '8:05 AM', date: 'Yesterday', type: 'Motion', color: '#3b82f6' }
  ]);

  return (
    <div style={{ fontFamily: 'system-ui', background: '#111827', color: '#f3f4f6', width: '100%', height: '100%', padding: 16, borderRadius: 8, boxSizing: 'border-box', display: 'flex', flexDirection: 'column' }}>
      <div style={{ fontSize: 14, fontWeight: 600, marginBottom: 12, color: '#9ca3af' }}>Doorbell History</div>
      <div style={{ flex: 1, overflow: 'auto', display: 'flex', flexDirection: 'column', gap: 8 }}>
        {events.map((e, i) => (
          <div key={i} style={{ display: 'flex', alignItems: 'center', gap: 10, background: '#1f2937', borderRadius: 8, padding: 10 }}>
            <div style={{ width: 48, height: 36, background: '#0f172a', borderRadius: 4, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 10, color: '#475569' }}>IMG</div>
            <div style={{ flex: 1, minWidth: 0 }}>
              <div style={{ fontSize: 13, fontWeight: 600, color: '#f3f4f6' }}>{e.type}</div>
              <div style={{ fontSize: 11, color: '#6b7280' }}>{e.date} at {e.time}</div>
            </div>
            <div style={{ width: 8, height: 8, borderRadius: '50%', background: e.color }} />
          </div>
        ))}
      </div>
    </div>
  );
}
render(<DoorbellHistory/>);
